import type { Plugin, Hooks } from '@opencode-ai/plugin'
import type { Part } from '@opencode-ai/sdk'
import { loadConfig } from './config'
import { getMode, setMode } from './state'
import { getCavemanSystemInstruction } from './skills/caveman'
import { handleCommit } from './commands/commit'
import { handleReview } from './commands/review'

const validModes = ['lite', 'full', 'ultra', 'wenyan-lite', 'wenyan-full', 'wenyan-ultra', 'off']

const cavemanPlugin: Plugin = async () => {
  const hooks: Hooks = {
    config: async (opencodeConfig) => {
      opencodeConfig.command ??= {}
      opencodeConfig.command['caveman'] = { template: '', description: 'Toggle caveman communication mode' }
      opencodeConfig.command['caveman-mode'] = { template: '', description: 'Toggle caveman communication mode' }
      opencodeConfig.command['caveman-commit'] = { template: '', description: 'Generate commit messages in caveman style' }
      opencodeConfig.command['caveman-review'] = { template: '', description: 'Review code in caveman style' }
    },

    'experimental.chat.system.transform': async (input, output) => {
      const cfg = loadConfig()
      if (!cfg.enabled || !cfg.features.caveman) return

      const sessionID = input.sessionID
      if (!sessionID) return

      let mode = getMode(sessionID)
      if (mode === 'off' || !mode) {
        mode = cfg.defaultMode
        if (mode !== 'off') {
          setMode(sessionID, mode)
        } else {
          return
        }
      }

      output.system.push(getCavemanSystemInstruction(mode))
    },

    'command.execute.before': async (input, output) => {
      const cfg = loadConfig()
      const cmd = (output as any).command ?? input.command
      const args = ((output as any).args ?? input.arguments).trim()
      const sessionID = input.sessionID

      if (cmd === 'caveman' || cmd === 'caveman-mode') {
        if (!cfg.features.caveman) {
          output.parts = [{ type: 'text', text: 'caveman feature disabled.' } as Part]
          return
        }
        const requested = args.toLowerCase()
        if (!requested) {
          output.parts = [{ type: 'text', text: `Mode: ${getMode(sessionID)}. Use /caveman-mode ${validModes.join('|')}` } as Part]
          return
        }
        if (!validModes.includes(requested)) {
          output.parts = [{ type: 'text', text: `Bad mode. Valid: ${validModes.join(', ')}` } as Part]
          return
        }
        setMode(sessionID, requested)
        if (requested === 'off') {
          output.parts = [{ type: 'text', text: 'Caveman mode off.' } as Part]
          return
        }
        output.parts = [{ type: 'text', text: `Caveman mode ${requested}.` } as Part]
        return
      }

      if (cmd === 'caveman-commit') {
        if (!cfg.features.commit) {
          output.parts = [{ type: 'text', text: 'commit feature disabled.' } as Part]
          return
        }
        const result = handleCommit(sessionID, args.split(/\s+/))
        output.parts = [{ type: 'text', text: result.systemInstruction || '' } as Part]
        return
      }

      if (cmd === 'caveman-review') {
        if (!cfg.features.review) {
          output.parts = [{ type: 'text', text: 'review feature disabled.' } as Part]
          return
        }
        const result = handleReview(sessionID, args.split(/\s+/))
        output.parts = [{ type: 'text', text: result.systemInstruction || '' } as Part]
        return
      }
    },
  }

  return hooks
}

export default cavemanPlugin

import { readFileSync, existsSync } from 'fs'
import { join } from 'path'
import { homedir } from 'os'
import { cwd } from 'process'

export interface CavemanConfig {
  enabled: boolean
  defaultMode: 'lite' | 'full' | 'ultra' | 'wenyan-lite' | 'wenyan-full' | 'wenyan-ultra' | 'off'
  features: {
    caveman: boolean
    commit: boolean
    review: boolean
  }
}

const defaults: CavemanConfig = {
  enabled: true,
  defaultMode: 'off',
  features: {
    caveman: true,
    commit: true,
    review: true,
  },
}

function loadConfigFile(path: string): Partial<CavemanConfig> | null {
  if (!existsSync(path)) return null
  try {
    return JSON.parse(readFileSync(path, 'utf-8')) as Partial<CavemanConfig>
  } catch {
    return null
  }
}

export function loadConfig(): CavemanConfig {
  const paths = [
    join(cwd(), 'caveman.json'),
    join(homedir(), '.config', 'opencode', 'caveman.json'),
  ]

  for (const path of paths) {
    const cfg = loadConfigFile(path)
    if (cfg) {
      return {
        ...defaults,
        ...cfg,
        features: { ...defaults.features, ...cfg.features },
      }
    }
  }

  return defaults
}

export interface CavemanState {
  currentMode: string
  featuresEnabled: { caveman: boolean; commit: boolean; review: boolean }
}

const stateMap = new Map<string, CavemanState>()

export function getState(sessionId: string): CavemanState {
  if (!stateMap.has(sessionId)) {
    stateMap.set(sessionId, {
      currentMode: 'off',
      featuresEnabled: { caveman: true, commit: true, review: true },
    })
  }
  return stateMap.get(sessionId)!
}

export function setMode(sessionId: string, mode: string): void {
  const state = getState(sessionId)
  state.currentMode = mode
}

export function getMode(sessionId: string): string {
  return getState(sessionId).currentMode
}

import { writeFileSync, existsSync } from 'fs'
import { join } from 'path'
import { cwd } from 'process'
import * as readline from 'readline'

const configPath = join(cwd(), 'caveman.json')

if (existsSync(configPath)) {
  console.log('caveman.json already exists. Edit it manually to change features.')
  process.exit(0)
}

const features = {
  caveman: true,
  commit: true,
  review: true,
}

const rl = readline.createInterface({ input: process.stdin, output: process.stdout })

const ask = (q: string): Promise<string> => new Promise(resolve => rl.question(q, resolve))

async function run() {
  console.log('🦴 Caveman Plugin Setup')
  console.log('Select features to enable (yes/no):\n')

  features.caveman = (await ask('Enable caveman communication mode? (yes): ')).toLowerCase() !== 'no'
  features.commit = (await ask('Enable /caveman-commit command? (yes): ')).toLowerCase() !== 'no'
  features.review = (await ask('Enable /caveman-review command? (yes): ')).toLowerCase() !== 'no'

  const defaultMode = features.caveman
    ? (await ask('Default mode (full/lite/ultra/wenyan-lite/wenyan-full/wenyan-ultra) [full]: ')) || 'full'
    : 'off'

  const config = {
    enabled: true,
    defaultMode,
    features,
  }

  writeFileSync(configPath, JSON.stringify(config, null, 2))
  console.log(`\n✅ Created ${configPath}`)
  rl.close()
}

run()

