import { loadConfig } from '../config'
import { getCommitSystemInstruction } from '../skills/commit'

export function handleCommit(sessionId: string, _args: string[]): { systemInstruction?: string; message?: string } {
  const cfg = loadConfig()
  if (!cfg.features.commit) {
    return { message: 'commit feature disabled.' }
  }

  return { systemInstruction: getCommitSystemInstruction() }
}

import { loadConfig } from '../config'
import { getReviewSystemInstruction } from '../skills/review'

export function handleReview(sessionId: string, _args: string[]): { systemInstruction?: string; message?: string } {
  const cfg = loadConfig()
  if (!cfg.features.review) {
    return { message: 'review feature disabled.' }
  }

  return { systemInstruction: getReviewSystemInstruction() }
}

import { setMode, getMode } from '../state'
import { loadConfig } from '../config'

const validModes = ['lite', 'full', 'ultra', 'wenyan-lite', 'wenyan-full', 'wenyan-ultra', 'off']

export function handleMode(sessionId: string, args: string[]): { systemInstruction?: string; message?: string } {
  const cfg = loadConfig()
  if (!cfg.features.caveman) {
    return { message: 'caveman feature disabled.' }
  }

  const requested = args[0]?.toLowerCase()

  if (!requested) {
    const mode = getMode(sessionId)
    return { message: `Mode: ${mode}. Use /caveman-mode ${validModes.join('|')}` }
  }

  if (!validModes.includes(requested)) {
    return { message: `Bad mode. Valid: ${validModes.join(', ')}` }
  }

  setMode(sessionId, requested)

  if (requested === 'off') {
    return { systemInstruction: 'You are a helpful assistant.', message: 'Caveman mode off.' }
  }

  return { message: `Caveman mode ${requested}.` }
}

import type { SessionState, WithParts } from "./state"
import type { Logger } from "./logger"
import type { PluginConfig } from "./config"
import { assignMessageRefs } from "./message-ids"
import {
    buildPriorityMap,
    buildToolIdList,
    injectCompressNudges,
    injectExtendedSubAgentResults,
    injectMessageIds,
    prune,
    stripHallucinations,
    stripHallucinationsFromString,
    stripStaleMetadata,
    syncCompressionBlocks,
} from "./messages"
import { renderSystemPrompt, type PromptStore } from "./prompts"
import { buildProtectedToolsExtension } from "./prompts/extensions/system"
import {
    applyPendingCompressionDurations,
    buildCompressionTimingKey,
    consumeCompressionStart,
    resolveCompressionDuration,
} from "./compress/timing"
import { filterMessages, filterMessagesInPlace } from "./messages/shape"
import {
    applyPendingManualTrigger,
    handleContextCommand,
    handleDecompressCommand,
    handleHelpCommand,
    handleManualToggleCommand,
    handleManualTriggerCommand,
    handleRecompressCommand,
    handleStatsCommand,
    handleSweepCommand,
} from "./commands"
import { type HostPermissionSnapshot } from "./host-permissions"
import { compressPermission, syncCompressPermissionState } from "./compress-permission"
import { checkSession, ensureSessionInitialized, saveSessionState, syncToolCache } from "./state"
import { cacheSystemPromptTokens } from "./ui/utils"

const INTERNAL_AGENT_SIGNATURES = [
    "You are a title generator",
    "You are a helpful AI assistant tasked with summarizing conversations",
    "You are an anchored context summarization assistant for coding sessions",
    "Summarize what was done in this conversation",
]

export function createSystemPromptHandler(
    state: SessionState,
    logger: Logger,
    config: PluginConfig,
    prompts: PromptStore,
) {
    return async (
        input: { sessionID?: string; model: { limit: { context: number } } },
        output: { system: string[] },
    ) => {
        if (input.model?.limit?.context) {
            state.modelContextLimit = input.model.limit.context
            logger.debug("Cached model context limit", { limit: state.modelContextLimit })
        }

        if (state.isSubAgent && !config.experimental.allowSubAgents) {
            return
        }

        const systemText = output.system.join("\n")
        if (INTERNAL_AGENT_SIGNATURES.some((sig) => systemText.includes(sig))) {
            logger.info("Skipping DCP system prompt injection for internal agent")
            return
        }

        const effectivePermission =
            input.sessionID && state.sessionId === input.sessionID
                ? compressPermission(state, config)
                : config.compress.permission

        if (effectivePermission === "deny") {
            return
        }

        prompts.reload()
        const runtimePrompts = prompts.getRuntimePrompts()
        const newPrompt = renderSystemPrompt(
            runtimePrompts,
            buildProtectedToolsExtension(config.compress.protectedTools),
            !!state.manualMode,
            state.isSubAgent && config.experimental.allowSubAgents,
        )
        if (output.system.length > 0) {
            output.system[output.system.length - 1] += "\n\n" + newPrompt
        } else {
            output.system.push(newPrompt)
        }
    }
}

export function createChatMessageTransformHandler(
    client: any,
    state: SessionState,
    logger: Logger,
    config: PluginConfig,
    prompts: PromptStore,
    hostPermissions: HostPermissionSnapshot,
) {
    return async (input: {}, output: { messages: WithParts[] }) => {
        const receivedMessages = Array.isArray(output.messages) ? output.messages.length : 0
        const messages = filterMessagesInPlace(output.messages)
        if (messages.length !== receivedMessages) {
            logger.warn("Skipping messages with unexpected shape during chat transform", {
                received: receivedMessages,
                usable: messages.length,
            })
        }

        await checkSession(client, state, logger, output.messages, config.manualMode.enabled)

        syncCompressPermissionState(state, config, hostPermissions, output.messages)

        if (state.isSubAgent && !config.experimental.allowSubAgents) {
            return
        }

        stripHallucinations(output.messages)
        cacheSystemPromptTokens(state, output.messages)
        assignMessageRefs(state, output.messages)
        syncCompressionBlocks(state, logger, output.messages)
        syncToolCache(state, config, logger, output.messages)
        buildToolIdList(state, output.messages)
        prune(state, logger, config, output.messages)
        await injectExtendedSubAgentResults(
            client,
            state,
            logger,
            output.messages,
            config.experimental.allowSubAgents,
        )
        const compressionPriorities = buildPriorityMap(config, state, output.messages)
        prompts.reload()
        injectCompressNudges(
            state,
            config,
            logger,
            output.messages,
            prompts.getRuntimePrompts(),
            compressionPriorities,
        )
        injectMessageIds(state, config, output.messages, compressionPriorities)
        applyPendingManualTrigger(state, output.messages, logger)
        stripStaleMetadata(output.messages)

        if (state.sessionId) {
            await logger.saveContext(state.sessionId, output.messages)
        }
    }
}

export function createCommandExecuteHandler(
    client: any,
    state: SessionState,
    logger: Logger,
    config: PluginConfig,
    workingDirectory: string,
    hostPermissions: HostPermissionSnapshot,
) {
    return async (
        input: { command: string; sessionID: string; arguments: string },
        output: { parts: any[] },
    ) => {
        if (!config.commands.enabled) {
            return
        }

        if (input.command === "dcp") {
            const messagesResponse = await client.session.messages({
                path: { id: input.sessionID },
            })
            const messages = filterMessages(messagesResponse.data || messagesResponse)

            await ensureSessionInitialized(
                client,
                state,
                input.sessionID,
                logger,
                messages,
                config.manualMode.enabled,
            )

            syncCompressPermissionState(state, config, hostPermissions, messages)

            const effectivePermission = compressPermission(state, config)
            if (effectivePermission === "deny") {
                return
            }

            const args = (input.arguments || "").trim().split(/\s+/).filter(Boolean)
            const subcommand = args[0]?.toLowerCase() || ""
            const subArgs = args.slice(1)

            const commandCtx = {
                client,
                state,
                config,
                logger,
                sessionId: input.sessionID,
                messages,
            }

            if (subcommand === "context") {
                await handleContextCommand(commandCtx)
                throw new Error("__DCP_CONTEXT_HANDLED__")
            }

            if (subcommand === "stats") {
                await handleStatsCommand(commandCtx)
                throw new Error("__DCP_STATS_HANDLED__")
            }

            if (subcommand === "sweep") {
                await handleSweepCommand({
                    ...commandCtx,
                    args: subArgs,
                    workingDirectory,
                })
                throw new Error("__DCP_SWEEP_HANDLED__")
            }

            if (subcommand === "manual") {
                await handleManualToggleCommand(commandCtx, subArgs[0]?.toLowerCase())
                throw new Error("__DCP_MANUAL_HANDLED__")
            }

            if (subcommand === "compress") {
                const userFocus = subArgs.join(" ").trim()
                const prompt = await handleManualTriggerCommand(commandCtx, "compress", userFocus)
                if (!prompt) {
                    throw new Error("__DCP_MANUAL_TRIGGER_BLOCKED__")
                }

                state.manualMode = "compress-pending"
                state.pendingManualTrigger = {
                    sessionId: input.sessionID,
                    prompt,
                }
                const rawArgs = (input.arguments || "").trim()
                output.parts.length = 0
                output.parts.push({
                    type: "text",
                    text: rawArgs ? `/dcp ${rawArgs}` : `/dcp ${subcommand}`,
                })
                return
            }

            if (subcommand === "decompress") {
                await handleDecompressCommand({
                    ...commandCtx,
                    args: subArgs,
                })
                throw new Error("__DCP_DECOMPRESS_HANDLED__")
            }

            if (subcommand === "recompress") {
                await handleRecompressCommand({
                    ...commandCtx,
                    args: subArgs,
                })
                throw new Error("__DCP_RECOMPRESS_HANDLED__")
            }

            await handleHelpCommand(commandCtx)
            throw new Error("__DCP_HELP_HANDLED__")
        }
    }
}

export function createTextCompleteHandler() {
    return async (
        _input: { sessionID: string; messageID: string; partID: string },
        output: { text: string },
    ) => {
        output.text = stripHallucinationsFromString(output.text)
    }
}

export function createEventHandler(state: SessionState, logger: Logger) {
    return async (input: { event: any }) => {
        const eventTime =
            typeof input.event?.time === "number" && Number.isFinite(input.event.time)
                ? input.event.time
                : typeof input.event?.properties?.time === "number" &&
                    Number.isFinite(input.event.properties.time)
                  ? input.event.properties.time
                  : undefined

        if (input.event.type !== "message.part.updated") {
            return
        }

        const part = input.event.properties?.part
        if (part?.type !== "tool" || part.tool !== "compress") {
            return
        }

        if (part.state.status === "pending") {
            if (typeof part.callID !== "string" || typeof part.messageID !== "string") {
                return
            }

            const startedAt = eventTime ?? Date.now()
            const key = buildCompressionTimingKey(part.messageID, part.callID)
            if (state.compressionTiming.startsByCallId.has(key)) {
                return
            }
            state.compressionTiming.startsByCallId.set(key, startedAt)
            logger.debug("Recorded compression start", {
                messageID: part.messageID,
                callID: part.callID,
                startedAt,
            })
            return
        }

        if (part.state.status === "completed") {
            if (typeof part.callID !== "string" || typeof part.messageID !== "string") {
                return
            }

            const key = buildCompressionTimingKey(part.messageID, part.callID)
            const start = consumeCompressionStart(state, part.messageID, part.callID)
            const durationMs = resolveCompressionDuration(start, eventTime, part.state.time)
            if (typeof durationMs !== "number") {
                return
            }

            state.compressionTiming.pendingByCallId.set(key, {
                messageId: part.messageID,
                callId: part.callID,
                durationMs,
            })

            const updates = applyPendingCompressionDurations(state)
            if (updates === 0) {
                return
            }

            await saveSessionState(state, logger)

            logger.info("Attached compression time to blocks", {
                messageID: part.messageID,
                callID: part.callID,
                blocks: updates,
                durationMs,
            })
            return
        }

        if (part.state.status === "running") {
            return
        }

        if (typeof part.callID === "string" && typeof part.messageID === "string") {
            state.compressionTiming.startsByCallId.delete(
                buildCompressionTimingKey(part.messageID, part.callID),
            )
        }
    }
}

import { fileURLToPath } from "url"
import path from "path"
import type { Plugin, ToolContext } from "@opencode-ai/plugin"
import type { Part } from "@opencode-ai/sdk"
import { loadActiveLevel } from "./tools/mode.ts"
import { systemRules, tailReminder, userNudge, compactionContext } from "./tools/rules.ts"
import { caveman_set_level } from "./tools/set-level.ts"
import type { CavemanLevel } from "./tools/mode.ts"

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const SKILLS_DIR = path.resolve(__dirname, "..", "..", "skills")

const COMMAND_ALIASES: Record<string, CavemanLevel> = {
  "caveman": "full",
  "caveman lite": "lite",
  "caveman full": "full",
  "caveman ultra": "ultra",
  "caveman-lite": "lite",
  "caveman-full": "full",
  "caveman-ultra": "ultra",
  "caveman-off": "off",
  "stop caveman": "off",
  "normal mode": "off",
}

/**
 * Returns the target CavemanLevel if the command+args string matches a caveman
 * command, or null if it is unrelated.
 */
function parseCavemanCommand(command: string, args: string): CavemanLevel | null {
  const raw = args.trim() ? `${command} ${args.trim()}` : command
  const normalized = raw.toLowerCase().trim()
  return COMMAND_ALIASES[normalized] ?? null
}

export const CavemanPlugin: Plugin = async (_ctx) => {
  return {
    tool: {
      caveman_set_level,
    },

    /**
     * Register the plugin's skills/ directory so opencode discovers
     * caveman-lite, caveman-full, caveman-ultra, caveman-off skills.
     */
    config: async (config: any) => {
      config.skills = config.skills || {}
      config.skills.paths = config.skills.paths || []
      if (!config.skills.paths.includes(SKILLS_DIR)) {
        config.skills.paths.push(SKILLS_DIR)
      }
    },

    /**
     * Inject caveman rules into the system prompt on every LLM call.
     * Equivalent to Claude Code's per-turn UserPromptSubmit hookSpecificOutput.
     * Rules are visible to the model every turn — prevents drift after /compact.
     *
     * Exploit U-shaped attention: full rules at top (highest priority position),
     * condensed reminder at bottom (last thing model reads before generating).
     * Middle context is most likely to be ignored by long-context models.
     */
    "experimental.chat.system.transform": async (_input, output) => {
      const level = loadActiveLevel()
      if (level === "off") return
      const concrete = level as Exclude<CavemanLevel, "off">
      output.system.unshift(systemRules(concrete))
      output.system.push(tailReminder(concrete))
    },

    /**
     * Append a synthetic reminder part to the LAST message every turn,
     * regardless of role. This guarantees the nudge sits immediately before
     * the model's next generation point — maximum recency.
     *
     * Why "last message" not "last user message":
     * - During tool loops (assistant → tool → assistant → tool…), the last
     *   message is often a tool result, not a user message. A reminder
     *   anchored to the last user msg gets buried under tool outputs.
     * - Anchoring to the absolute tail keeps the nudge adjacent to the
     *   generation point on every turn, regardless of conversation shape.
     *
     * Marked synthetic so UI can hide it. Single nudge per turn → ~30 tokens.
     */
    "experimental.chat.messages.transform": async (_input, output) => {
      const level = loadActiveLevel()
      if (level === "off") return
      const concrete = level as Exclude<CavemanLevel, "off">

      const last = output.messages[output.messages.length - 1]
      if (!last) return

      last.parts.push({
        id: crypto.randomUUID(),
        sessionID: last.info.sessionID,
        messageID: last.info.id,
        type: "text",
        text: userNudge(concrete),
        synthetic: true,
      } as Part)
    },

    /**
     * Shape the compaction summary to include caveman mode.
     * The model writes the summary — if we tell it to include caveman state,
     * the resulting summary will re-activate caveman on the next turn.
     */
    "experimental.session.compacting": async (_input, output) => {
      const level = loadActiveLevel()
      if (level === "off") return
      output.context.push(compactionContext(level as Exclude<CavemanLevel, "off">))
    },

    /**
     * Intercept /caveman commands before they reach the model.
     * Parses the command, switches mode, informs model via mutated parts.
     */
    "command.execute.before": async (input, output) => {
      const parsed = parseCavemanCommand(input.command, input.arguments)
      if (!parsed) return

      // Fire set-level logic directly — avoid a round-trip through the model.
      // ask() is never called by this tool so the cast is safe.
      const ctx = {
        sessionID: input.sessionID,
        messageID: "",
        agent: "",
        directory: "",
        worktree: "",
        abort: new AbortController().signal,
        metadata: () => {},
        ask: (() => {}) as unknown as ToolContext["ask"],
      }
      const result = await caveman_set_level.execute({ level: parsed }, ctx)

      output.parts.push({
        type: "text",
        id: crypto.randomUUID(),
        sessionID: input.sessionID,
        messageID: "",
        text: typeof result === "string" ? result : result.output,
      } as Part)
    },
  }
}

